# === Kings Bay Plowshares 7 ===

php artisan prisoner:add '{"name":"Mark Colville","first_name":"Mark","last_name":"Colville","description":"Mark Colville is a New Haven, Connecticut Catholic Worker who has been a member of the Plowshares anti-nuclear movement since the 1990s. On April 4, 2018 — the 50th anniversary of Martin Luther King Jr.s assassination — he was one of seven Catholic activists who entered the Kings Bay Naval Submarine Base in Georgia, the East Coast home port of the Trident nuclear submarine fleet. Using household tools, blood, and indictment papers, the Kings Bay Plowshares 7 began symbolic disarmament of Trident. They were arrested on the base. A federal jury in Brunswick, Georgia convicted all seven on October 24, 2019 of conspiracy, destruction of government property, depredation, and trespassing. He was sentenced to 21 months in federal prison.","state":"Connecticut","race":"White","gender":"Male","ideologies":["Anti-nuclear","Catholic Worker","Plowshares"],"affiliation":["Catholic Worker","Plowshares","Kings Bay Plowshares 7"],"era":"2010s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Georgia","charges":"Federal conspiracy, destruction of government property, depredation, and trespassing — April 4, 2018 Kings Bay Plowshares action against Trident nuclear submarines","arrest_date":"2018-04-04","incarceration_date":"2018-04-04","sentenced_date":"2020-10-15","sentence":"21 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the Southern District of Georgia, October 24, 2019"}]}' || true

php artisan prisoner:add '{"name":"Martha Hennessy","first_name":"Martha","last_name":"Hennessy","description":"Martha Hennessy is a Catholic Worker peace activist and the granddaughter of Catholic Worker Movement co-founder Dorothy Day. On April 4, 2018 she was one of the seven Catholic activists known as the Kings Bay Plowshares 7 who entered the Kings Bay Naval Submarine Base in Georgia to symbolically disarm the Trident nuclear submarine fleet. She was convicted by a federal jury on October 24, 2019 of conspiracy, destruction of government property, depredation, and trespassing, and was sentenced to 10 months in federal prison.","state":"Vermont","race":"White","gender":"Female","ideologies":["Anti-nuclear","Catholic Worker","Plowshares"],"affiliation":["Catholic Worker","Plowshares","Kings Bay Plowshares 7"],"era":"2010s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Georgia","charges":"Federal conspiracy, destruction of government property, depredation, and trespassing — April 4, 2018 Kings Bay Plowshares action","arrest_date":"2018-04-04","incarceration_date":"2018-04-04","sentenced_date":"2020-11-13","sentence":"10 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the Southern District of Georgia, October 24, 2019"}]}' || true

php artisan prisoner:add '{"name":"Clare Grady","first_name":"Clare","last_name":"Grady","description":"Clare Grady is an Ithaca, New York Catholic Worker peace activist with decades of involvement in the Plowshares anti-nuclear movement. On April 4, 2018 she was one of the seven Catholic activists known as the Kings Bay Plowshares 7 who entered the Kings Bay Naval Submarine Base in Georgia to symbolically disarm the Trident nuclear submarine fleet. She was convicted by a federal jury on October 24, 2019 of conspiracy, destruction of government property, depredation, and trespassing, and was sentenced to 12 months in federal prison.","state":"New York","race":"White","gender":"Female","ideologies":["Anti-nuclear","Catholic Worker","Plowshares"],"affiliation":["Catholic Worker","Plowshares","Kings Bay Plowshares 7"],"era":"2010s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Georgia","charges":"Federal conspiracy, destruction of government property, depredation, and trespassing — April 4, 2018 Kings Bay Plowshares action","arrest_date":"2018-04-04","incarceration_date":"2018-04-04","sentenced_date":"2020-11-13","sentence":"12 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the Southern District of Georgia, October 24, 2019"}]}' || true

php artisan prisoner:add '{"name":"Patrick O Neill","first_name":"Patrick","last_name":"O Neill","description":"Patrick O Neill is a North Carolina Catholic Worker peace activist and co-founder of the Father Charlie Mulholland Catholic Worker House in Garner, North Carolina. On April 4, 2018 he was one of the seven Catholic activists known as the Kings Bay Plowshares 7 who entered the Kings Bay Naval Submarine Base in Georgia to symbolically disarm the Trident nuclear submarine fleet. He was convicted by a federal jury on October 24, 2019 of conspiracy, destruction of government property, depredation, and trespassing, and was sentenced to 14 months in federal prison.","state":"North Carolina","race":"White","gender":"Male","ideologies":["Anti-nuclear","Catholic Worker","Plowshares"],"affiliation":["Catholic Worker","Plowshares","Kings Bay Plowshares 7"],"era":"2010s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Georgia","charges":"Federal conspiracy, destruction of government property, depredation, and trespassing — April 4, 2018 Kings Bay Plowshares action","arrest_date":"2018-04-04","incarceration_date":"2018-04-04","sentenced_date":"2021-05-26","sentence":"14 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the Southern District of Georgia, October 24, 2019"}]}' || true

php artisan prisoner:add '{"name":"Steve Kelly","first_name":"Steve","last_name":"Kelly","description":"Steve Kelly is a Jesuit priest and longtime Plowshares anti-nuclear activist who has spent more than a decade of his life in U.S. federal prison for repeated symbolic disarmament actions. On April 4, 2018 he was one of the seven Catholic activists known as the Kings Bay Plowshares 7 who entered the Kings Bay Naval Submarine Base in Georgia to symbolically disarm the Trident nuclear submarine fleet. He was convicted by a federal jury on October 24, 2019 of conspiracy, destruction of government property, depredation, and trespassing, and was held in pretrial detention for the entire two and a half years between the action and his sentencing because he had refused to accept the conditions of pretrial release. He was sentenced to time served — 33 months — in October 2020 and immediately released.","state":"California","race":"White","gender":"Male","ideologies":["Anti-nuclear","Catholic","Plowshares"],"affiliation":["Society of Jesus","Plowshares","Kings Bay Plowshares 7"],"era":"2010s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Georgia","charges":"Federal conspiracy, destruction of government property, depredation, and trespassing — April 4, 2018 Kings Bay Plowshares action","arrest_date":"2018-04-04","incarceration_date":"2018-04-04","sentenced_date":"2020-10-29","sentence":"33 months federal prison (time served at sentencing)","convicted":"Yes — federal jury verdict, U.S. District Court for the Southern District of Georgia, October 24, 2019"}]}' || true

php artisan prisoner:add '{"name":"Carmen Trotta","first_name":"Carmen","last_name":"Trotta","description":"Carmen Trotta is a longtime member of the St. Joseph House Catholic Worker in New York Citys Lower East Side. On April 4, 2018 he was one of the seven Catholic activists known as the Kings Bay Plowshares 7 who entered the Kings Bay Naval Submarine Base in Georgia to symbolically disarm the Trident nuclear submarine fleet. He was convicted by a federal jury on October 24, 2019 of conspiracy, destruction of government property, depredation, and trespassing, and was sentenced to 14 months in federal prison.","state":"New York","race":"White","gender":"Male","ideologies":["Anti-nuclear","Catholic Worker","Plowshares"],"affiliation":["Catholic Worker","St. Joseph House","Kings Bay Plowshares 7"],"era":"2010s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Georgia","charges":"Federal conspiracy, destruction of government property, depredation, and trespassing — April 4, 2018 Kings Bay Plowshares action","arrest_date":"2018-04-04","incarceration_date":"2018-04-04","sentenced_date":"2020-11-13","sentence":"14 months federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the Southern District of Georgia, October 24, 2019"}]}' || true

# === Resistance Conspiracy Case (May 12, 1988) ===

php artisan prisoner:add '{"name":"Marilyn Buck","first_name":"Marilyn","middle_name":"Jean","last_name":"Buck","description":"Marilyn Jean Buck was a white anti-imperialist revolutionary, longtime ally of the Black Liberation Army, and one of the most important U.S. political prisoners of the post-COINTELPRO generation. She was first arrested in 1973 for purchasing two boxes of 9mm ammunition in California using a false ID for the Black Liberation Army, and convicted in federal court of weapons charges. While on furlough in 1977 she went underground; she was a participant in the November 2, 1979 successful liberation of Assata Shakur from the New Jersey state prison at Clinton. She was recaptured on May 11, 1985 in New York. In 1988 she was named in the Resistance Conspiracy indictment alongside Linda Evans, Laura Whitehorn, Susan Rosenberg, Tim Blunk, and Alan Berkman, charged with the 1983-85 Armed Resistance Unit bombings of the U.S. Capitol, Fort McNair, the Washington Navy Yard, and four New York City sites. In 1988 she was sentenced to 50 years in federal prison for the Brinks-related charges and 80 years for the Resistance Conspiracy charges, to run consecutively. She was released on July 15, 2010 after serving 25 years; she died of complications of uterine sarcoma 20 days later, on August 3, 2010, age 62.","state":"New York","race":"White","gender":"Female","birthdate":"1947-12-13","death_date":"2010-08-03","ideologies":["Anti-imperialist","Black Liberation solidarity","Communist"],"affiliation":["Black Liberation Army","Armed Resistance Unit"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal weapons charges (1973); 1985 Brinks-related charges including conspiracy and aiding Assata Shakurs 1979 liberation; 1988 Resistance Conspiracy — 1983-85 Armed Resistance Unit bombings of U.S. Capitol, Fort McNair, Washington Navy Yard, plus NYC sites","arrest_date":"1985-05-11","incarceration_date":"1985-05-11","release_date":"2010-07-15","sentence":"50 years (Brinks-related) plus 80 years (Resistance Conspiracy) consecutive; released after 25 years","convicted":"Yes — federal jury verdicts and pleas, multiple cases"}]}' || true

php artisan prisoner:add '{"name":"Linda Evans","first_name":"Linda","middle_name":"Sue","last_name":"Evans","description":"Linda Sue Evans is a longtime anti-imperialist organizer and former member of Students for a Democratic Society and the Weather Underground. Arrested on May 11, 1985 in New York with co-defendants in the Armed Resistance Unit, she was first convicted in 1986 in U.S. District Court for the Southern District of New York for using false identification to purchase firearms and was sentenced to 35 years in federal prison. In May 1988 she was named in the Resistance Conspiracy indictment for the 1983-85 Armed Resistance Unit bombings. In 1990 she pleaded guilty to conspiracy and destruction of government property and was sentenced to an additional 5 years consecutive. On the last day of his presidency, January 20, 2001, President Clinton commuted her sentence; she was released on January 24, 2001 after 16 years in federal prison.","state":"New York","race":"White","gender":"Female","ideologies":["Anti-imperialist","Communist","Anti-racist"],"affiliation":["Students for a Democratic Society","Weather Underground","Armed Resistance Unit"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal firearms charges (1986) and Resistance Conspiracy — 1983-85 Armed Resistance Unit bombings of U.S. Capitol, Fort McNair, Washington Navy Yard, plus NYC sites","arrest_date":"1985-05-11","incarceration_date":"1985-05-11","release_date":"2001-01-24","sentence":"35 years (firearms) plus 5 years (Resistance Conspiracy) consecutive; commuted by President Clinton January 20, 2001","convicted":"Yes — 1986 jury verdict + 1990 guilty plea"}]}' || true

php artisan prisoner:add '{"name":"Susan Rosenberg","first_name":"Susan","last_name":"Rosenberg","description":"Susan Rosenberg is a former member of the May 19th Communist Organization and an anti-imperialist revolutionary. On November 29, 1984 she was arrested in Cherry Hill, New Jersey, with co-defendant Tim Blunk while transferring 740 pounds of dynamite, weapons, and false identification papers from a storage unit. In 1985 she was convicted in U.S. District Court for the District of New Jersey of weapons and explosives charges and sentenced to 58 years in federal prison — at the time the longest sentence ever imposed for federal weapons possession. In May 1988 she was named in the Resistance Conspiracy indictment. The Resistance Conspiracy charges against her were ultimately dropped because she was already serving her 58-year sentence. On the last day of his presidency, January 20, 2001, President Clinton commuted her sentence; she was released after 16 years. She has since become a writer, an editor, and an anti-prison advocate, and her memoir An American Radical was published in 2011.","state":"New Jersey","race":"White","gender":"Female","ideologies":["Anti-imperialist","Communist"],"affiliation":["May 19th Communist Organization"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"New Jersey","charges":"Federal weapons and explosives possession (1984); 1988 Resistance Conspiracy indictment (charges dropped because of pending sentence)","arrest_date":"1984-11-29","incarceration_date":"1984-11-29","release_date":"2001-01-20","sentence":"58 years federal prison (weapons/explosives); commuted by President Clinton January 20, 2001 after 16 years","convicted":"Yes — federal jury verdict, U.S. District Court for the District of New Jersey, 1985"}]}' || true

php artisan prisoner:add '{"name":"Laura Whitehorn","first_name":"Laura","last_name":"Whitehorn","description":"Laura Whitehorn is a longtime anti-imperialist organizer and former member of the May 19th Communist Organization. She was arrested on May 12, 1988 along with Marilyn Buck, Linda Evans, Susan Rosenberg, Tim Blunk, and Alan Berkman as one of the six defendants in the Resistance Conspiracy Case — the federal prosecution of the 1983-85 Armed Resistance Unit bombings of the U.S. Capitol, Fort McNair, the Washington Navy Yard, and four New York City sites. In September 1990 she pleaded guilty to conspiracy and destruction of government property; on December 6, 1990 Federal District Judge Harold H. Greene sentenced her to 20 years in federal prison. She was released in August 1999 after 14 years and has been a leading post-release organizer for U.S. political prisoner amnesty.","state":"New York","race":"White","gender":"Female","ideologies":["Anti-imperialist","Communist","LGBTQ"],"affiliation":["May 19th Communist Organization"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Resistance Conspiracy — 1983-85 Armed Resistance Unit bombings of U.S. Capitol, Fort McNair, Washington Navy Yard, plus four NYC sites","arrest_date":"1988-05-12","incarceration_date":"1988-05-12","release_date":"1999-08-15","sentence":"20 years federal prison; released after 14 years","convicted":"Yes — guilty plea, U.S. District Court for the District of Columbia, September 1990"}]}' || true

php artisan prisoner:add '{"name":"Timothy Blunk","first_name":"Timothy","last_name":"Blunk","aka":"Tim Blunk","description":"Timothy Blunk is a former May 19th Communist Organization member who was arrested with Susan Rosenberg in Cherry Hill, New Jersey on November 29, 1984 while transferring 740 pounds of dynamite, weapons, and false identification papers. In 1985 he was convicted in U.S. District Court for the District of New Jersey of weapons and explosives charges and sentenced to 58 years in federal prison. In May 1988 he was named in the Resistance Conspiracy indictment, but the additional charges were dropped because of his pending sentence. He was released in 1996 after the U.S. Parole Commission revisited his sentence in light of changed federal sentencing guidelines.","state":"New Jersey","race":"White","gender":"Male","ideologies":["Anti-imperialist","Communist"],"affiliation":["May 19th Communist Organization"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"New Jersey","charges":"Federal weapons and explosives possession; 1988 Resistance Conspiracy indictment (charges dropped because of pending sentence)","arrest_date":"1984-11-29","incarceration_date":"1984-11-29","release_date":"1996-09-15","sentence":"58 years federal prison; released after 12 years","convicted":"Yes — federal jury verdict, U.S. District Court for the District of New Jersey, 1985"}]}' || true

php artisan prisoner:add '{"name":"Alan Berkman","first_name":"Alan","last_name":"Berkman","description":"Alan Berkman was a New York City physician and longtime member of the radical health-care collectives that grew out of the 1970s anti-imperialist left, including the Lincoln Detox program in the South Bronx. He was arrested on May 23, 1985 in connection with the failed October 20, 1981 Brinks armored-car robbery in Nyack, New York, and held without bond for the duration of pretrial proceedings. While held in federal custody he was diagnosed with Hodgkins lymphoma; the failure of the federal Bureau of Prisons to provide adequate cancer treatment became an international campaign and is widely cited as a foundational case in U.S. prisoner-medical-rights litigation. In May 1988 he was named in the Resistance Conspiracy indictment for the 1983-85 Armed Resistance Unit bombings; the additional charges were dropped because of his pending sentence. He was sentenced to 10 years in federal prison and released in 1992. After release he became a leading public-health figure in international AIDS activism and the founder of Health GAP, the U.S. organization that campaigned successfully for universal access to AIDS medication in the global South. He died on June 5, 2009 of complications from the cancer that had begun during his imprisonment.","state":"New York","race":"White","gender":"Male","death_date":"2009-06-05","ideologies":["Anti-imperialist","Communist","Medical justice"],"affiliation":["May 19th Communist Organization","Lincoln Detox","Health GAP"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal charges in connection with the October 20, 1981 Brinks armored-car robbery in Nyack, New York; 1988 Resistance Conspiracy indictment (charges dropped because of pending sentence)","arrest_date":"1985-05-23","incarceration_date":"1985-05-23","release_date":"1992-06-15","sentence":"10 years federal prison; released after 7 years","convicted":"Yes — federal court conviction"}]}' || true

# === Ohio 7 / United Freedom Front ===

php artisan prisoner:add '{"name":"Raymond Luc Levasseur","first_name":"Raymond","middle_name":"Luc","last_name":"Levasseur","description":"Raymond Luc Levasseur was a working-class Maine-born organizer of the United Freedom Front, the small clandestine anti-imperialist organization that conducted bombings and bank expropriations in solidarity with the Black liberation movement, the Puerto Rican independence movement, and Central American and Southern African liberation struggles between 1976 and 1984. He was arrested on November 4, 1984 in Deerfield, Ohio along with his partner Patricia Gros Levasseur, after FBI agents pulled over their van; their three young daughters were in the vehicle.\n\nHe was convicted in federal court in 1986 in the Brooklyn-based seditious-conspiracy and bombing prosecution and sentenced to 45 years in federal prison. Most of his sentence was served at the federal Administrative Maximum Facility (ADX) at Florence, Colorado. He was released on November 8, 2004 after 20 years. The 1989 Massachusetts seditious-conspiracy retrial of the Ohio 7 — separate from the Brooklyn case — ended in acquittals on the sedition counts and a hung jury on the rest, and is widely regarded as one of the most important political-prosecution defeats of the post-COINTELPRO era.","state":"Ohio","race":"White","gender":"Male","birthdate":"1946-10-10","ideologies":["Anti-imperialist","Communist","Anti-racist"],"affiliation":["United Freedom Front","Sam Melville-Jonathan Jackson Unit"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (ADX Florence)","institution_city":"Florence","institution_state":"Colorado","charges":"Federal seditious conspiracy, racketeering, and bombing — 1976-84 United Freedom Front bombings of military and corporate targets in solidarity with Black liberation, Puerto Rican independence, and Central American liberation movements","arrest_date":"1984-11-04","incarceration_date":"1984-11-04","release_date":"2004-11-08","sentence":"45 years federal prison; released after 20 years","convicted":"Yes — federal jury verdict, U.S. District Court for the Eastern District of New York, 1986"}]}' || true

php artisan prisoner:add '{"name":"Patricia Gros Levasseur","first_name":"Patricia","middle_name":"Gros","last_name":"Levasseur","description":"Patricia Gros Levasseur was a member of the United Freedom Front and the partner of Raymond Luc Levasseur. She was arrested with him on November 4, 1984 in Deerfield, Ohio, with their three young daughters in the family van. She was convicted in 1986 in the Brooklyn-based federal United Freedom Front prosecution and sentenced to a federal prison term shorter than her partners. The 1989 Massachusetts seditious-conspiracy retrial of the Ohio 7 ended in acquittals on the sedition counts.","state":"Ohio","race":"White","gender":"Female","ideologies":["Anti-imperialist","Communist"],"affiliation":["United Freedom Front"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal racketeering and bombing — United Freedom Front 1976-84 actions","arrest_date":"1984-11-04","incarceration_date":"1984-11-04","sentence":"Federal prison term","convicted":"Yes — federal jury verdict, U.S. District Court for the Eastern District of New York, 1986"}]}' || true

php artisan prisoner:add '{"name":"Tom Manning","first_name":"Tom","last_name":"Manning","description":"Thomas Manning was a working-class Vietnam War U.S. Marine veteran and one of the central organizers of the United Freedom Front. He was arrested with co-defendant Richard Williams in Richmond, Virginia in 1985, several months after the November 1984 capture of the Levasseurs and the rest of the Ohio 7. He was convicted in 1986 in federal court in Brooklyn of seditious conspiracy, racketeering, and bombing in connection with the 1976-84 United Freedom Front actions, and sentenced to 53 years in federal prison. He and Williams were also tried in New Jersey state court for the 1981 killing of New Jersey State Trooper Philip Lamonaco in a roadside shootout — both were convicted and sentenced to life in prison. He died in federal custody on July 30, 2019.","state":"Massachusetts","race":"White","gender":"Male","death_date":"2019-07-30","ideologies":["Anti-imperialist","Communist"],"affiliation":["United Freedom Front","U.S. Marine Corps (Vietnam)"],"era":"1980s","in_custody":false,"released":false,"cases":[{"institution_name":"Federal Bureau of Prisons","charges":"Federal seditious conspiracy, racketeering, and bombing (1976-84 United Freedom Front actions); New Jersey state murder of Trooper Philip Lamonaco (1981)","arrest_date":"1985-04-24","incarceration_date":"1985-04-24","death_in_custody_date":"2019-07-30","sentence":"53 years federal prison + life sentence (NJ state); died in custody July 30, 2019","convicted":"Yes — 1986 federal conviction + NJ state murder conviction"}]}' || true

php artisan prisoner:add '{"name":"Carol Ann Manning","first_name":"Carol","middle_name":"Ann","last_name":"Manning","description":"Carol Ann Manning was a member of the United Freedom Front and the wife of Tom Manning. She was arrested with him in Richmond, Virginia in 1985, several months after the November 1984 capture of the Levasseurs. She was convicted in 1986 in federal court in Brooklyn and sentenced to 15 years in federal prison.","state":"Massachusetts","race":"White","gender":"Female","ideologies":["Anti-imperialist","Communist"],"affiliation":["United Freedom Front"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal racketeering and bombing — 1976-84 United Freedom Front actions","arrest_date":"1985-04-24","incarceration_date":"1985-04-24","sentence":"15 years federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the Eastern District of New York, 1986"}]}' || true

php artisan prisoner:add '{"name":"Richard Williams","first_name":"Richard","middle_name":"Charles","last_name":"Williams","description":"Richard Charles Williams was a member of the United Freedom Front. He was arrested in Cleveland, Ohio in November 1984, shortly after the Levasseurs were captured in Deerfield. He was convicted in 1986 in federal court in Brooklyn and sentenced to 45 years in federal prison. He and Tom Manning were also tried in New Jersey state court for the 1981 killing of New Jersey State Trooper Philip Lamonaco in a roadside shootout — both were convicted and sentenced to life in prison. He died in federal custody on December 6, 2005.","state":"Ohio","race":"White","gender":"Male","death_date":"2005-12-06","ideologies":["Anti-imperialist","Communist"],"affiliation":["United Freedom Front"],"era":"1980s","in_custody":false,"released":false,"cases":[{"institution_name":"Federal Bureau of Prisons","charges":"Federal seditious conspiracy, racketeering, and bombing (1976-84 United Freedom Front); New Jersey state murder of Trooper Philip Lamonaco (1981)","arrest_date":"1984-11-08","incarceration_date":"1984-11-08","death_in_custody_date":"2005-12-06","sentence":"45 years federal prison + life sentence (NJ state); died in custody December 6, 2005","convicted":"Yes — 1986 federal conviction + NJ state murder conviction"}]}' || true

php artisan prisoner:add '{"name":"Jaan Karl Laaman","first_name":"Jaan","middle_name":"Karl","last_name":"Laaman","description":"Jaan Karl Laaman is an Estonian-born anti-imperialist who emigrated to the United States as a child. He was a member of the United Freedom Front and was arrested in Cleveland, Ohio in November 1984, shortly after the Levasseurs. He was convicted in 1986 in federal court in Brooklyn of seditious conspiracy, racketeering, and bombing in connection with the 1976-84 United Freedom Front actions, and sentenced to 53 years in federal prison. He was also convicted of the 1982 attempted murder of two Massachusetts state troopers in a roadside shootout. He has been held throughout the federal prison system, including the Communications Management Unit at Marion, Illinois. As of 2024 he had served forty years and was the only Ohio 7 defendant other than the deceased still in federal custody. The Jericho Movement lists him among its current political prisoners.","state":"Massachusetts","race":"White","gender":"Male","ideologies":["Anti-imperialist","Communist"],"affiliation":["United Freedom Front"],"era":"1980s","in_custody":true,"released":false,"cases":[{"institution_name":"Federal Bureau of Prisons (Communications Management Unit, Marion)","institution_state":"Illinois","charges":"Federal seditious conspiracy, racketeering, and bombing (1976-84 United Freedom Front); MA state attempted murder of two state troopers (1982)","arrest_date":"1984-11-04","incarceration_date":"1984-11-04","sentence":"53 years federal prison + MA state attempted murder","convicted":"Yes — 1986 federal conviction + MA state conviction"}]}' || true

php artisan prisoner:add '{"name":"Barbara Curzi-Laaman","first_name":"Barbara","last_name":"Curzi-Laaman","description":"Barbara Curzi-Laaman was a member of the United Freedom Front and the partner of Jaan Karl Laaman. She was arrested in Cleveland, Ohio in November 1984, shortly after the Levasseurs were captured in Deerfield. She was convicted in 1986 in federal court in Brooklyn and sentenced to 15 years in federal prison.","state":"Ohio","race":"White","gender":"Female","ideologies":["Anti-imperialist","Communist"],"affiliation":["United Freedom Front"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal racketeering and bombing — 1976-84 United Freedom Front actions","arrest_date":"1984-11-08","incarceration_date":"1984-11-08","sentence":"15 years federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the Eastern District of New York, 1986"}]}' || true

php artisan prisoner:add '{"name":"Kazi Toure","first_name":"Kazi","last_name":"Toure","description":"Kazi Toure (born Christopher King) was a Black member of the United Freedom Front, arrested in 1982 — earlier than the Ohio 7. In 1986 he was tried in U.S. District Court in Boston in the federal sedition prosecution that grew out of the UFFs Boston-area activity, the case for which the historian Howard Zinn served as defense expert witness. He was convicted of seditious conspiracy and sentenced to a federal prison term, served, and released. He has been an outspoken voice in U.S. political-prisoner support work since.","state":"Massachusetts","race":"Black","gender":"Male","ideologies":["Anti-imperialist","Black Liberation","Communist"],"affiliation":["United Freedom Front"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal seditious conspiracy — 1976-84 United Freedom Front actions","arrest_date":"1982-04-01","incarceration_date":"1982-04-01","sentence":"Federal prison term","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Massachusetts, 1986"}]}' || true

# === Los Macheteros ===

php artisan prisoner:add '{"name":"Filiberto Ojeda Rios","first_name":"Filiberto","middle_name":"Innocencio","last_name":"Ojeda Rios","description":"Filiberto Ojeda Ríos was a Cuban-trained Puerto Rican Communist and the founder and lifelong leader of the Ejército Popular Boricua-Macheteros, the clandestine armed wing of the Puerto Rican independence movement that emerged in the late 1970s. He was the principal organizer of the September 12, 1983 Wells Fargo armored-car expropriation in West Hartford, Connecticut, which netted $7,017,151 — the second-largest cash robbery in U.S. history at the time. He was arrested in the August 30, 1985 mass FBI raid in Puerto Rico (more than 200 agents involved) but jumped bond in 1990 and lived underground in Puerto Rico for the next fifteen years.\n\nOn September 23, 2005 — the anniversary of the 1868 Grito de Lares — more than 100 FBI agents surrounded his rural home in Hormigueros, Puerto Rico. He was shot once in the upper torso during the standoff and was left to bleed to death over many hours after the agents withdrew. The Justice Departments later admission that no medical attention was provided after the shot was widely condemned across the Puerto Rican political spectrum, and his death is regarded by the Puerto Rican left as an extrajudicial killing.","state":"Puerto Rico","race":"Hispanic","gender":"Male","birthdate":"1933-04-26","death_date":"2005-09-23","ideologies":["Puerto Rican Independence","Communist","Anti-imperialist"],"affiliation":["Ejercito Popular Boricua-Macheteros"],"era":"1980s","in_custody":false,"released":false,"cases":[{"institution_name":"Federal Bureau of Prisons (jumped bond 1990)","institution_state":"Puerto Rico","charges":"Federal seditious conspiracy and racketeering — 1983 Wells Fargo expropriation in West Hartford, Connecticut","arrest_date":"1985-08-30","incarceration_date":"1985-08-30","death_in_custody_date":"2005-09-23","sentence":"Bonded out 1985; jumped bond 1990; killed by FBI September 23, 2005 in Hormigueros, Puerto Rico","convicted":"Indicted 1985; not convicted at time of death"}]}' || true

php artisan prisoner:add '{"name":"Juan Segarra Palmer","first_name":"Juan","last_name":"Segarra Palmer","description":"Juan Segarra Palmer was a Harvard-educated Puerto Rican independentista and a leader of Los Macheteros. He was the principal driver of the September 12, 1983 Wells Fargo expropriation in West Hartford, Connecticut. He was arrested in the August 30, 1985 mass FBI raid in Puerto Rico and convicted at trial in 1989 in U.S. District Court in Hartford. He was sentenced to 65 years in federal prison. After 19 years President Clinton commuted his sentence on his last day in office, January 20, 2001; he was released on May 2, 2004 after the federal Bureau of Prisons completed his good-time calculation.","state":"Puerto Rico","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["Ejercito Popular Boricua-Macheteros"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Connecticut","charges":"Federal seditious conspiracy and racketeering — 1983 Wells Fargo expropriation in West Hartford, Connecticut","arrest_date":"1985-08-30","incarceration_date":"1985-08-30","release_date":"2004-05-02","sentence":"65 years federal prison; commuted by President Clinton January 20, 2001; released after 19 years","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Connecticut, 1989"}]}' || true

php artisan prisoner:add '{"name":"Antonio Camacho Negron","first_name":"Antonio","last_name":"Camacho Negron","description":"Antonio Camacho Negrón was a member of Los Macheteros arrested in the August 30, 1985 mass FBI raid in Puerto Rico for his role in the September 12, 1983 Wells Fargo expropriation in West Hartford, Connecticut. He was convicted at trial in 1989 in U.S. District Court in Hartford. After serving his federal sentence he returned to Puerto Rico, where he later refused to comply with U.S. probation supervision and was returned to federal prison; he was finally released in 2014.","state":"Puerto Rico","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["Ejercito Popular Boricua-Macheteros"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Connecticut","charges":"Federal seditious conspiracy and racketeering — 1983 Wells Fargo expropriation in West Hartford, Connecticut","arrest_date":"1985-08-30","incarceration_date":"1985-08-30","release_date":"2014-08-15","sentence":"Federal prison term + return to custody for refusing probation supervision","convicted":"Yes — federal jury verdict, U.S. District Court for the District of Connecticut, 1989"}]}' || true

php artisan prisoner:add '{"name":"Avelino Gonzalez Claudio","first_name":"Avelino","last_name":"Gonzalez Claudio","description":"Avelino González Claudio was a Macheteros member who organized the transport of cash from the September 12, 1983 Wells Fargo expropriation in West Hartford, Connecticut. He went underground after the August 30, 1985 mass FBI raid in Puerto Rico and lived in clandestinity in Puerto Rico for nearly 23 years until his arrest on February 7, 2008. He pleaded guilty in 2010 to conspiracy and was sentenced to 7 years in federal prison. He was released in 2013.","state":"Puerto Rico","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["Ejercito Popular Boricua-Macheteros"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Connecticut","charges":"Federal conspiracy — role in transporting funds from the 1983 Wells Fargo expropriation in West Hartford, Connecticut","arrest_date":"2008-02-07","incarceration_date":"2008-02-07","release_date":"2013-12-15","sentence":"7 years federal prison","convicted":"Yes — guilty plea, U.S. District Court for the District of Connecticut, 2010"}]}' || true

php artisan prisoner:add '{"name":"Norberto Gonzalez Claudio","first_name":"Norberto","last_name":"Gonzalez Claudio","description":"Norberto González Claudio was the brother of fellow Macheteros member Avelino González Claudio. He went underground after the August 30, 1985 mass FBI raid in Puerto Rico and lived in clandestinity for almost 26 years until his arrest in May 2011 in the central mountains of Puerto Rico. He pleaded guilty in 2012 to conspiracy related to the 1983 Wells Fargo expropriation and was sentenced to 5 years in federal prison. He was released in 2017.","state":"Puerto Rico","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["Ejercito Popular Boricua-Macheteros"],"era":"2010s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Connecticut","charges":"Federal conspiracy — role in 1983 Wells Fargo expropriation in West Hartford, Connecticut","arrest_date":"2011-05-09","incarceration_date":"2011-05-09","release_date":"2017-06-15","sentence":"5 years federal prison","convicted":"Yes — guilty plea, U.S. District Court for the District of Connecticut, 2012"}]}' || true

# === Major BLA / Black liberation elders (verify if already in DB) ===

php artisan prisoner:add '{"name":"Sundiata Acoli","first_name":"Sundiata","last_name":"Acoli","aka":"Clark Squire","description":"Sundiata Acoli, born Clark Squire in Decatur, Texas in 1937, is a former NASA mathematician, member of the Harlem chapter of the Black Panther Party, and Black Liberation Army soldier. He was one of the original Panther 21 defendants — twenty-one New York Panthers acquitted in May 1971 of conspiring to bomb New York police stations. After the Panther 21 acquittal he went underground with the BLA. On May 2, 1973 he was a passenger in the car driven by Assata Shakur on the New Jersey Turnpike when state troopers pulled them over; in the ensuing shootout New Jersey State Trooper Werner Foerster was killed and BLA member Zayd Malik Shakur was killed. He was convicted of Trooper Foersters murder in 1974 and sentenced to life plus 30 years in New Jersey state prison.\n\nHe was repeatedly denied parole over the next four decades despite multiple clean disciplinary records and intervention by national civil-rights organizations. The Jericho Movement, of which he was a co-founder in 1998, made him one of its central campaigns. On May 11, 2022 the New Jersey Supreme Court ordered him paroled, ruling that the parole board had abused its discretion in continuing to deny release. He was released on May 26, 2022, age 85, after 49 years of imprisonment.","state":"New Jersey","race":"Black","gender":"Male","birthdate":"1937-01-14","ideologies":["Black Liberation","New Afrikan Independence"],"affiliation":["Black Panther Party","Black Liberation Army","Panther 21","Jericho Movement"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"New Jersey Department of Corrections","institution_state":"New Jersey","charges":"Murder of New Jersey State Trooper Werner Foerster — May 2, 1973 New Jersey Turnpike shootout","arrest_date":"1973-05-02","incarceration_date":"1973-05-02","release_date":"2022-05-26","sentence":"Life plus 30 years; paroled by New Jersey Supreme Court order after 49 years","convicted":"Yes — New Jersey state murder conviction, 1974"}]}' || true

php artisan prisoner:add '{"name":"Mutulu Shakur","first_name":"Mutulu","last_name":"Shakur","aka":"Jeral Wayne Williams","description":"Dr. Mutulu Shakur, born Jeral Wayne Williams in Baltimore in 1950, was a New Afrikan acupuncturist, Black Liberation Army member, and the stepfather of the rapper Tupac Shakur. He was a co-founder of the Lincoln Detox program in the South Bronx and the Black Acupuncture Advisory Association of North America. He was indicted in 1986 for conspiracy in connection with the failed October 20, 1981 Brinks armored-car robbery in Nyack, New York, and the 1979 liberation of Assata Shakur from the New Jersey state prison at Clinton. After four years on the FBI Most Wanted list he was arrested on February 11, 1986. In 1988 he was convicted of RICO conspiracy and sentenced to 60 years in federal prison.\n\nHe was repeatedly denied compassionate release as his health collapsed; the federal Bureau of Prisons and U.S. Parole Commission resisted release for the entire decade after he became eligible in 2017. On December 16, 2022, dying of bone-marrow cancer, he was finally granted compassionate release after 36 years in federal prison. He died on July 7, 2023, age 72, less than seven months after his release.","state":"New York","race":"Black","gender":"Male","birthdate":"1950-08-08","death_date":"2023-07-07","ideologies":["Black Liberation","New Afrikan Independence","Public health"],"affiliation":["Black Liberation Army","Republic of New Afrika","Lincoln Detox","Black Acupuncture Advisory Association of North America"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"RICO conspiracy in connection with the October 20, 1981 Brinks armored-car robbery in Nyack, New York, and the November 2, 1979 liberation of Assata Shakur","arrest_date":"1986-02-11","incarceration_date":"1986-02-11","release_date":"2022-12-16","sentence":"60 years federal prison; compassionate release December 2022 after 36 years","convicted":"Yes — federal RICO conviction, 1988"}]}' || true

php artisan prisoner:add '{"name":"Russell Maroon Shoatz","first_name":"Russell","last_name":"Shoatz","aka":"Maroon","description":"Russell Maroon Shoatz was a former Black Panther Party member, founder of the Black Unity Council in Philadelphia, and one of the longest-held political prisoners in U.S. history. He was convicted in 1972 of the August 29, 1970 killing of a Philadelphia police officer in Fairmount Park, in a case that he and his defense team always argued was a frame-up rooted in the Philadelphia Panthers conflict with the Frank Rizzo police department. He spent the next 49 years in Pennsylvania state prison, more than 22 of them in continuous solitary confinement at the State Correctional Institution at Greene supermax — making him the longest continuously-held solitary-confinement prisoner in Pennsylvania history.\n\nHe escaped twice — in 1977 (recaptured after 27 days) and in 1980 (recaptured after 6 days, after which he chose Maroon as his prison name in tribute to the New World African self-emancipated communities). His writings on prison organizing, masculine accountability, and revolutionary feminism were collected in Maroon the Implacable: The Collected Writings of Russell Maroon Shoatz (PM Press, 2013), with a foreword by Mumia Abu-Jamal. He was finally released on compassionate parole on October 26, 2021 at age 78, suffering from advanced cancer; he died at his sisters home on December 17, 2021, just 52 days after his release.","state":"Pennsylvania","race":"Black","gender":"Male","birthdate":"1943-08-23","death_date":"2021-12-17","ideologies":["Black Liberation","New Afrikan Independence","Anti-prison"],"affiliation":["Black Panther Party","Black Unity Council"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections (SCI Greene supermax)","institution_state":"Pennsylvania","charges":"Murder of a Philadelphia police officer in Fairmount Park, August 29, 1970 — defense argued frame-up","arrest_date":"1972-01-28","incarceration_date":"1972-01-28","release_date":"2021-10-26","sentence":"Life imprisonment; compassionate release after 49 years (with 22+ years in continuous solitary confinement)","convicted":"Yes — Pennsylvania state murder conviction, 1972"}]}' || true

php artisan prisoner:add '{"name":"Sekou Odinga","first_name":"Sekou","last_name":"Odinga","aka":"Nathaniel Burns","description":"Sekou Odinga, born Nathaniel Burns in Queens, New York in 1944, was a co-founder of the Bronx chapter of the Black Panther Party, a Black Liberation Army soldier, and one of the principal architects of the November 2, 1979 liberation of Assata Shakur from the New Jersey state prison at Clinton. He was captured on October 23, 1981 in Queens after a shootout with the NYPD that left him with multiple gunshot wounds; he was tortured by NYPD officers in the hospital and at the precinct. In 1984 he was convicted in U.S. District Court for the Southern District of New York of conspiracy in connection with the Brinks robbery and the Shakur liberation, and was sentenced to 40 years in federal prison plus 25 years on a parallel state conviction. He served 33 years and was released on November 25, 2014 at age 70. He died on January 12, 2024, age 79, after a decade of post-release political-prisoner organizing including with the Jericho Movement.","state":"New York","race":"Black","gender":"Male","birthdate":"1944-06-17","death_date":"2024-01-12","ideologies":["Black Liberation","New Afrikan Independence"],"affiliation":["Black Panther Party","Black Liberation Army","Republic of New Afrika","Jericho Movement"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Federal conspiracy in connection with the October 20, 1981 Brinks armored-car robbery in Nyack, New York, and the November 2, 1979 liberation of Assata Shakur","arrest_date":"1981-10-23","incarceration_date":"1981-10-23","release_date":"2014-11-25","sentence":"40 years federal prison + 25 years state; released after 33 years","convicted":"Yes — 1984 federal conviction"}]}' || true

